// Check multi-threading rules before sending
// If someone from same company already responded, skip other contacts
const items = $input.all();
const staticData = $getWorkflowStaticData('global');
const respondedCompanies = staticData.respondedCompanies || {};

const toSend = [];
const skipped = [];

for (const item of items) {
  const company = item.json.company_name?.toLowerCase() || '';

  if (respondedCompanies[company]) {
    skipped.push({
      json: {
        ...item.json,
        skip_reason: `Company already responded via ${respondedCompanies[company]}`,
        status: 'skipped_company_responded'
      }
    });
  } else {
    toSend.push(item);
  }
}

// Return items to send
return toSend.length > 0 ? toSend : [{ json: { no_emails_to_send: true } }];

// Format for SmartLead API campaign creation
const items = $input.all().filter(i => !i.json.no_emails_to_send);

if (items.length === 0) return [];

// Group by campaign
const campaigns = new Map();

for (const item of items) {
  const campaignId = item.json.campaign_id || 'default';
  if (!campaigns.has(campaignId)) {
    campaigns.set(campaignId, []);
  }
  campaigns.get(campaignId).push(item.json);
}

// Format for SmartLead
const smartleadPayloads = [];
for (const [campaignId, emails] of campaigns) {
  for (const email of emails) {
    smartleadPayloads.push({
      json: {
        email_address: email.email,
        first_name: email.full_name?.split(' ')[0] || '',
        last_name: email.full_name?.split(' ').slice(1).join(' ') || '',
        company_name: email.company_name,
        subject: email.subject,
        body: email.body,
        campaign_id: campaignId,
        thread_id: email.thread_id,
        sequence_number: email.sequence_number,
        airtable_record_id: email.id || email.record_id,

        // SmartLead specific fields
        custom_fields: {
          job_title: email.job_title || '',
          contact_rank: email.contact_rank || 1
        }
      }
    });
  }
}

return smartleadPayloads;

