// Update Airtable records to mark as sent/queued
const items = $input.all();
return items.map(item => ({
  json: {
    record_id: item.json.airtable_record_id,
    sent: true,
    status: 'queued_in_smartlead',
    queued_at: new Date().toISOString(),
    smartlead_response: item.json
  }
}));
